# ─── CoAP Protocol Constants ───
COAP_VERSION = 1
COAP_TYPE_CON = 0  # Confirmable
COAP_TYPE_NON = 1  # Non-confirmable
COAP_TYPE_ACK = 2  # Acknowledgement
COAP_TYPE_RST = 3  # Reset

COAP_METHOD_GET = 1
COAP_METHOD_POST = 2
COAP_METHOD_PUT = 3
COAP_METHOD_DELETE = 4

COAP_RESPONSE_CONTENT = (2, 5)       # 2.05 Content
COAP_RESPONSE_CHANGED = (2, 4)       # 2.04 Changed
COAP_RESPONSE_BAD_REQUEST = (4, 0)   # 4.00 Bad Request
COAP_RESPONSE_NOT_FOUND = (4, 4)     # 4.04 Not Found
COAP_RESPONSE_METHOD_NOT_ALLOWED = (4, 5)  # 4.05 Method Not Allowed

COAP_OPTION_URI_PATH = 11
COAP_OPTION_CONTENT_FORMAT = 12

COAP_CONTENT_FORMAT_TEXT = 0
COAP_CONTENT_FORMAT_JSON = 50

COAP_PORT = 5683


class CoapMessage:
    """Lightweight CoAP message parser and builder."""

    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = COAP_TYPE_CON
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage."""
        msg = CoapMessage()
        if len(data) < 4:
            return None

        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.msg_type = (first_byte >> 4) & 0x03
        token_length = first_byte & 0x0F

        code_byte = data[1]
        msg.code_class = (code_byte >> 5) & 0x07
        msg.code_detail = code_byte & 0x1F

        msg.message_id = (data[2] << 8) | data[3]

        offset = 4
        if token_length > 0 and offset + token_length <= len(data):
            msg.token = data[offset:offset + token_length]
            offset += token_length

        # Parse options
        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            option_number = prev_option_number + option_delta
            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append((option_number, option_value))
            prev_option_number = option_number

        return msg

    def get_uri_path(self):
        """Extract URI path from options."""
        parts = []
        for opt_num, opt_val in self.options:
            if opt_num == COAP_OPTION_URI_PATH:
                parts.append(opt_val.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def get_method(self):
        """Return method code (GET=1, POST=2, PUT=3, DELETE=4)."""
        if self.code_class == 0:
            return self.code_detail
        return 0

    def build_response(self, code_class, code_detail, payload=b'',
                       content_format=COAP_CONTENT_FORMAT_JSON):
        """Build a response message as bytes."""
        resp = CoapMessage()
        resp.version = COAP_VERSION
        resp.msg_type = COAP_TYPE_ACK if self.msg_type == COAP_TYPE_CON else COAP_TYPE_NON
        resp.code_class = code_class
        resp.code_detail = code_detail
        resp.message_id = self.message_id
        resp.token = self.token
        resp.payload = payload if isinstance(payload, bytes) else payload.encode('utf-8')

        # Build raw bytes
        token_length = len(resp.token)
        first_byte = ((resp.version & 0x03) << 6) | \
                     ((resp.msg_type & 0x03) << 4) | \
                     (token_length & 0x0F)

        code_byte = ((resp.code_class & 0x07) << 5) | (resp.code_detail & 0x1F)

        result = bytearray()
        result.append(first_byte)
        result.append(code_byte)
        result.append((resp.message_id >> 8) & 0xFF)
        result.append(resp.message_id & 0xFF)

        if token_length > 0:
            result.extend(resp.token)

        # Add Content-Format option if we have payload
        if resp.payload:
            # Option delta for Content-Format (12)
            option_delta = COAP_OPTION_CONTENT_FORMAT
            if option_delta < 13:
                option_header = (option_delta << 4) | 1  # length = 1 byte
                result.append(option_header)
            else:
                result.append(0xD1)  # delta extended by 1 byte, length = 1
                result.append(option_delta - 13)
            result.append(content_format & 0xFF)

            # Payload marker
            result.append(0xFF)
            result.extend(resp.payload)

        return bytes(result)


class DeviceState:
    """Manages all device resources with thread-safe access."""

    def __init__(self):
        self._lock = _thread.allocate_lock()
        self._temperature = 22.5
        self._humidity = 55.0
        self._pressure = 1013.25
        self._light_on = False
        self._light_brightness = 0
        self._fan_on = False
        self._fan_speed = 0
        self._adc = None

        # Try to initialize ADC for real temperature reading
        try:
            self._adc = machine.ADC(4)  # Internal temp sensor on RP2040
        except Exception:
            pass

    def read_temperature(self):
        """Read temperature from sensor or return simulated value."""
        if self._adc:
            try:
                raw = self._adc.read_u16()
                voltage = raw * 3.3 / 65535
                temp = 27.0 - (voltage - 0.706) / 0.001721
                self._temperature = round(temp, 1)
            except Exception:
                pass
        return self._temperature

    def get_sensor_data(self, sensor_type):
        """Get sensor reading by type."""
        self._lock.acquire()
        try:
            if sensor_type == 'temp':
                return {
                    'value': self.read_temperature(),
                    'unit': 'celsius',
                    'timestamp': time.time()
                }
            elif sensor_type == 'humidity':
                return {
                    'value': self._humidity,
                    'unit': 'percent',
                    'timestamp': time.time()
                }
            elif sensor_type == 'pressure':
                return {
                    'value': self._pressure,
                    'unit': 'hPa',
                    'timestamp': time.time()
                }
            else:
                return None
        finally:
            self._lock.release()

    def get_all_sensors(self):
        """Get all sensor readings."""
        self._lock.acquire()
        try:
            return {
                'temp': {'value': self.read_temperature(), 'unit': 'celsius'},
                'humidity': {'value': self._humidity, 'unit': 'percent'},
                'pressure': {'value': self._pressure, 'unit': 'hPa'},
                'timestamp': time.time()
            }
        finally:
            self._lock.release()

    def get_actuator_state(self, actuator_type):
        """Get actuator state by type."""
        self._lock.acquire()
        try:
            if actuator_type == 'light':
                return {
                    'on': self._light_on,
                    'brightness': self._light_brightness,
                    'timestamp': time.time()
                }
            elif actuator_type == 'fan':
                return {
                    'on': self._fan_on,
                    'speed': self._fan_speed,
                    'timestamp': time.time()
                }
            else:
                return None
        finally:
            self._lock.release()

    def set_actuator_state(self, actuator_type, data):
        """Set actuator state. Returns (success, state_dict)."""
        self._lock.acquire()
        try:
            if actuator_type == 'light':
                if 'on' in data:
                    self._light_on = bool(data['on'])
                if 'brightness' in data:
                    val = int(data['brightness'])
                    self._light_brightness = max(0, min(100, val))
                # Drive actual GPIO if available
                self._apply_light_state()
                return True, self.get_actuator_state.__wrapped__(self, 'light') if False else {
                    'on': self._light_on,
                    'brightness': self._light_brightness,
                    'timestamp': time.time()
                }
            elif actuator_type == 'fan':
                if 'on' in data:
                    self._fan_on = bool(data['on'])
                if 'speed' in data:
                    val = int(data['speed'])
                    self._fan_speed = max(0, min(100, val))
                self._apply_fan_state()
                return True, {
                    'on': self._fan_on,
                    'speed': self._fan_speed,
                    'timestamp': time.time()
                }
            else:
                return False, None
        except (ValueError, KeyError, TypeError) as e:
            return False, {'error': str(e)}
        finally:
            self._lock.release()

    def _apply_light_state(self):
        """Apply light state to hardware GPIO/PWM."""
        try:
            led = machine.Pin("LED", machine.Pin.OUT)
            led.value(1 if self._light_on else 0)
        except Exception:
            try:
                led = machine.Pin(25, machine.Pin.OUT)
                led.value(1 if self._light_on else 0)
            except Exception:
                pass

    def _apply_fan_state(self):
        """Apply fan state to hardware GPIO/PWM."""
        try:
            # Example: PWM on GPIO 15 for fan control
            fan_pin = machine.Pin(15, machine.Pin.OUT)
            if self._fan_on and self._fan_speed > 0:
                pwm = machine.PWM(fan_pin)
                pwm.freq(1000)
                pwm.duty_u16(int(self._fan_speed / 100 * 65535))
            else:
                fan_pin.value(0)
        except Exception:
            pass


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.sock = None
        self.running = False
        self.device = DeviceState()
        self.routes = {}
        self._request_count = 0
        self._setup_routes()

    def _setup_routes(self):
        """Register all resource handlers."""
        # Sensor resources (GET only)
        self.routes['/sensors/temp'] = {
            'GET': self._handle_get_temp,
        }
        self.routes['/sensors/humidity'] = {
            'GET': self._handle_get_humidity,
        }
        self.routes['/sensors/pressure'] = {
            'GET': self._handle_get_pressure,
        }
        self.routes['/sensors'] = {
            'GET': self._handle_get_all_sensors,
        }

        # Actuator resources (GET and PUT)
        self.routes['/actuators/light'] = {
            'GET': self._handle_get_light,
            'PUT': self._handle_put_light,
        }
        self.routes['/actuators/fan'] = {
            'GET': self._handle_get_fan,
            'PUT': self._handle_put_fan,
        }

        # Discovery / well-known
        self.routes['/.well-known/core'] = {
            'GET': self._handle_well_known,
        }

        # Device info
        self.routes['/device'] = {
            'GET': self._handle_get_device_info,
        }

    # ─── Sensor Handlers ───

    def _handle_get_temp(self, request):
        data = self.device.get_sensor_data('temp')
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _handle_get_humidity(self, request):
        data = self.device.get_sensor_data('humidity')
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _handle_get_pressure(self, request):
        data = self.device.get_sensor_data('pressure')
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _handle_get_all_sensors(self, request):
        data = self.device.get_all_sensors()
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    # ─── Actuator Handlers ───

    def _handle_get_light(self, request):
        data = self.device.get_actuator_state('light')
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _handle_put_light(self, request):
        try:
            data = json.loads(request.payload.decode('utf-8'))
        except (ValueError, UnicodeError):
            return request.build_response(
                *COAP_RESPONSE_BAD_REQUEST,
                payload='{"error":"Invalid JSON"}'
            )
        success, state = self.device.set_actuator_state('light', data)
        if success:
            payload = json.dumps(state)
            return request.build_response(*COAP_RESPONSE_CHANGED, payload=payload)
        else:
            return request.build_response(
                *COAP_RESPONSE_BAD_REQUEST,
                payload=json.dumps(state) if state else '{"error":"Failed"}'
            )

    def _handle_get_fan(self, request):
        data = self.device.get_actuator_state('fan')
        payload = json.dumps(data)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _handle_put_fan(self, request):
        try:
            data = json.loads(request.payload.decode('utf-8'))
        except (ValueError, UnicodeError):
            return request.build_response(
                *COAP_RESPONSE_BAD_REQUEST,
                payload='{"error":"Invalid JSON"}'
            )
        success, state = self.device.set_actuator_state('fan', data)
        if success:
            payload = json.dumps(state)
            return request.build_response(*COAP_RESPONSE_CHANGED, payload=payload)
        else:
            return request.build_response(
                *COAP_RESPONSE_BAD_REQUEST,
                payload=json.dumps(state) if state else '{"error":"Failed"}'
            )

    # ─── Discovery & Info ───

    def _handle_well_known(self, request):
        """CoRE Link Format discovery."""
        links = []
        for path in sorted(self.routes.keys()):
            if path == '/.well-known/core':
                continue
            methods = list(self.routes[path].keys())
            if 'sensors' in path:
                rt = 'sensor'
            elif 'actuators' in path:
                rt = 'actuator'
            else:
                rt = 'device'
            link = '<{}>;rt="{}";ct=50'.format(path, rt)
            links.append(link)
        payload = ','.join(links)
        return request.build_response(
            *COAP_RESPONSE_CONTENT,
            payload=payload,
            content_format=COAP_CONTENT_FORMAT_TEXT
        )

    def _handle_get_device_info(self, request):
        info = {
            'name': 'micropython-coap-node',
            'version': '1.0.0',
            'uptime': time.time(),
            'requests_served': self._request_count,
            'resources': list(self.routes.keys()),
            'mem_free': self._get_free_memory()
        }
        payload = json.dumps(info)
        return request.build_response(*COAP_RESPONSE_CONTENT, payload=payload)

    def _get_free_memory(self):
        """Get free memory in bytes."""
        try:
            import gc
            gc.collect()
            return gc.mem_free()
        except Exception:
            return -1

    # ─── Request Routing ───

    def _method_name(self, code):
        methods = {1: 'GET', 2: 'POST', 3: 'PUT', 4: 'DELETE'}
        return methods.get(code, 'UNKNOWN')

    def _handle_request(self, request, addr):
        """Route a parsed CoAP request to the appropriate handler."""
        uri = request.get_uri_path()
        method = self._method_name(request.get_method())

        print("[CoAP] {} {} from {}:{}".format(method, uri, addr[0], addr[1]))
        self._request_count += 1

        # Look up route
        if uri in self.routes:
            route_handlers = self.routes[uri]
            if method in route_handlers:
                return route_handlers[method](request)
            else:
                return request.build_response(
                    *COAP_RESPONSE_METHOD_NOT_ALLOWED,
                    payload=json.dumps({
                        'error': 'Method not allowed',
                        'allowed': list(route_handlers.keys())
                    })
                )
        else:
            return request.build_response(
                *COAP_RESPONSE_NOT_FOUND,
                payload=json.dumps({
                    'error': 'Resource not found',
                    'path': uri
                })
            )

    # ─── Network Setup ───

    def _connect_wifi(self, ssid, password, timeout=15):
        """Connect to WiFi network."""
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)

        if wlan.isconnected():
            print("[WiFi] Already connected: {}".format(wlan.ifconfig()[0]))
            return wlan.ifconfig()[0]

        print("[WiFi] Connecting to '{}'...".format(ssid))
        wlan.connect(ssid, password)

        start = time.time()
        while not wlan.isconnected():
            if time.time() - start > timeout:
                raise OSError("WiFi connection timeout")
            time.sleep(0.5)

        ip = wlan.ifconfig()[0]
        print("[WiFi] Connected: {}".format(ip))
        return ip

    # ─── Server Loop ───

    def start(self, ssid=None, password=None):
        """Start the CoAP server."""
        # Connect to WiFi if credentials provided
        if ssid:
            try:
                self.host = self._connect_wifi(ssid, password)
            except Exception as e:
                print("[WiFi] Error: {}".format(e))
                print("[WiFi] Starting on 0.0.0.0 (AP mode or wired)")

        # Create UDP socket
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.settimeout(1.0)  # 1 second timeout for graceful shutdown

        self.running = True

        print("=" * 50)
        print(" CoAP Server running on coap://{}:{}".format(self.host, self.port))
        print(" Resources:")
        for path in sorted(self.routes.keys()):
            methods = list(self.routes[path].keys())
            print("   {} [{}]".format(path, ', '.join(methods)))
        print("=" * 50)

        # Garbage collect before entering main loop
        try:
            import gc
            gc.collect()
        except ImportError:
            pass

        while self.running:
            try:
                data, addr = self.sock.recvfrom(256)  # CoAP messages are small
                if data:
                    request = CoapMessage.parse(data)
                    if request and request.version == COAP_VERSION:
                        response = self._handle_request(request, addr)
                        if response:
                            self.sock.sendto(response, addr)
                    else:
                        print("[CoAP] Invalid message from {}:{}".format(addr[0], addr[1]))

            except OSError as e:
                # Timeout is expected (allows checking self.running)
                if 'ETIMEDOUT' not in str(e) and 'timed out' not in str(e):
                    print("[CoAP] Socket error: {}".format(e))

            except Exception as e:
                print("[CoAP] Error: {}".format(e))

            # Periodic garbage collection to keep memory stable
            if self._request_count % 50 == 0 and self._request_count > 0:
                try:
                    import gc
                    gc.collect()
                except ImportError:
                    pass

    def stop(self):
        """Stop the CoAP server."""
        print("[CoAP] Shutting down...")
        self.running = False
        if self.sock:
            try:
                self.sock.close()
            except Exception:
                pass
        print("[CoAP] Server stopped.")


# ─── Main Entry Point ───

def main():
    """
    Main entry point for the CoAP IoT server.

    Usage examples with coap-client (libcoap):
        coap-client -m get coap://<device-ip>/sensors/temp
        coap-client -m get coap://<device-ip>/sensors
        coap-client -m get coap://<device-ip>/actuators/light
        coap-client -m put coap://<device-ip>/actuators/light -e '{"on":true,"brightness":75}'
        coap-client -m put coap://<device-ip>/actuators/fan -e '{"on":true,"speed":50}'
        coap-client -m get coap://<device-ip>/.well-known/core
        coap-client -m get coap://<device-ip>/device
    """

    # ── Configuration ──
    WIFI_SSID = "YourWiFiSSID"
    WIFI_PASSWORD = "YourWiFiPassword"
    COAP_SERVER_PORT = 5683

    server = CoapServer(port=COAP_SERVER_PORT)

    try:
        # Pass WiFi credentials to auto-connect, or None to skip
        server.start(ssid=WIFI_SSID, password=WIFI_PASSWORD)
    except KeyboardInterrupt:
        server.stop()
    except Exception as e:
        print("[FATAL] {}".format(e))
        server.stop()


if __name__ == '__main__':
    main()